# Good: processing logic is a pure function, testable in isolation
def compute_user_total(events: list[dict]) -> dict[str, float]:
    totals = {}
    for e in events:
        totals[e["user_id"]] = totals.get(e["user_id"], 0) + e["amount"]
    return totals

# Unit test — no Kafka, no Flink needed
def test_compute_user_total():
    events = [
        {"user_id": "u1", "amount": 100},
        {"user_id": "u1", "amount": 50},
    ]
    result = compute_user_total(events)
    assert result["u1"] == 150
